import React, { useEffect, useState } from 'react'
import { Img_URL, fetchGenreList } from '../../utils/fetchApi';
import { Link } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';

const Genres = () => {
  const[genreId,setGenreId]=useState('28');
  const [page,setPage]=useState(1);
  const [GenresList,setGenresList]=useState([])

  const loadMoreHandle=()=>{
   setPage((prev)=> {
    console.log(prev);
    return prev += 1;
   });
   refetch();
   setGenresList((prev)=> [...prev,...PopularList]);
 }

  const { isLoading,isError,error ,data: PopularList,refetch} = useQuery({
      queryKey: ["PopularList"],
      // keepPreviousData: true,
      // staleTime:60000,
      queryFn: () =>
        fetchGenreList(`${genreId}`,`${page}`).then((res) => {
          if(page===1){
            setGenresList(res.results);
          }
          console.log(res.results);
          return res.results;
        }),
    });



    useEffect(()=>{
      refetch();
    },[refetch,page]);

    if (isLoading) {
      return (
        <div className="loading">
          <h1>Loading...</h1>
        </div>
      );
    } else if (isError) {
      return (
        <div className="error">
          <p>{error.message}</p>
        </div>
      );
    } else
return (
  <div className="Popular">
        <h1>Popular Movies</h1>
        <div>
        <select name="genre" id="genre" onChange={(e)=> setGenreId(e.target.value)}>
        {
            genre.map((item)=>(
              <option key={item.id} value={item.id}>{item.name}</option>
            ))
          }
          </select>
        {GenresList?.map((item,index) => (
            <Link to={`/movie/${item.id}`} className="card" key={index}>
              <img src={`${Img_URL}${item.poster_path}`} alt="img" />
            </Link>
        ))}
        </div>
        <button onClick={loadMoreHandle}>More</button>
      </div>
)
}

export default Genres
